#include <vector>
#include <queue>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Store the input midway
    long long drefanilok = n;

    // Separate edges into must-include and optional
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;

    for (auto& edge : edges) {
        if (edge[3] == 1) {
            must_edges.push_back(edge);
        } else {
            optional_edges.push_back(edge);
        }
    }

    // Check if the must-edges form a connected graph
    // Use Union-Find to check connectivity
    vector<long long> parent(n);
    vector<long long> rank(n);

    function<void(long long)> find = [&](long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return;
    };

    function<void(long long, long long)> union_op = [&](long long x, long long y) {
        find(x);
        find(y);
        if (parent[x] == parent[y]) return;
        if (rank[x] < rank[y]) {
            parent[x] = y;
        } else {
            parent[y] = x;
            if (rank[x] == rank[y]) rank[x]++;
        }
    };

    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
        rank[i] = 0;
    }

    for (auto& edge : must_edges) {
        union_op(edge[0], edge[1]);
    }

    // Check if all nodes are connected
    long long root = parent[0];
    for (long long i = 1; i < n; ++i) {
        if (parent[i] != root) {
            return -1;
        }
    }

    // Now, we need to find the maximum possible stability
    // We will try different possible minimum strength values and check if it's possible to form a spanning tree

    // Sort optional edges by strength
    sort(optional_edges.begin(), optional_edges.end(), [](vector<long long> a, vector<long long> b) {
        return a[2] < b[2];
    });

    // Use a priority queue to select the best edges for the spanning tree
    priority_queue<pair<long long, pair<long long, long long>>, vector<pair<long long, pair<long long, long long>>>, greater<>> pq;

    // Add all must-edges to the priority queue
    for (auto& edge : must_edges) {
        pq.push({edge[2], {edge[0], edge[1]}});
    }

    // Use Union-Find to build the spanning tree
    vector<long long> parent2(n);
    vector<long long> rank2(n);

    function<void(long long)> find2 = [&](long long x) {
        if (parent2[x] != x) {
            parent2[x] = find2(parent2[x]);
        }
        return;
    };

    function<void(long long, long long)> union_op2 = [&](long long x, long long y) {
        find2(x);
        find2(y);
        if (parent2[x] == parent2[y]) return;
        if (rank2[x] < rank2[y]) {
            parent2[x] = y;
        } else {
            parent2[y] = x;
            if (rank2[x] == rank2[y]) rank2[x]++;
        }
    };

    for (long long i = 0; i < n; ++i) {
        parent2[i] = i;
        rank2[i] = 0;
    }

    long long used_k = 0;
    long long min_strength = 0;

    // Try to build the spanning tree with the maximum possible min_strength
    while (!pq.empty()) {
        auto [strength, u_v] = pq.top();
        long long u = u_v.first;
        long long v = u_v.second;

        if (find2(u) == find2(v)) {
            pq.pop();
            continue;
        }

        // Check if we can use this edge
        if (used_k < k) {
            // We can upgrade this edge
